import{_ as b,o as e,c as t,j as r,a as p,a1 as l}from"./chunks/framework.Bp7r_-XI.js";const N=JSON.parse('{"title":"朱可夫NUK17双持冲锋枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/朱可夫NUK17双持冲锋枪.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/朱可夫NUK17双持冲锋枪.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/朱可夫NUK17双持冲锋枪.md"};function n(s,a,i,d,_,c){return e(),t("div",null,[...a[0]||(a[0]=[r("h1",{id:"朱可夫nuk17双持冲锋枪",tabindex:"-1"},[p("朱可夫NUK17双持冲锋枪 "),r("a",{class:"header-anchor",href:"#朱可夫nuk17双持冲锋枪","aria-label":'Permalink to "朱可夫NUK17双持冲锋枪"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调014")])])],-1),l('<h1 id="朱可夫nuk17双持冲锋枪-1" tabindex="-1">朱可夫NUK17双持冲锋枪 <a class="header-anchor" href="#朱可夫nuk17双持冲锋枪-1" aria-label="Permalink to &quot;朱可夫NUK17双持冲锋枪&quot;">​</a></h1><p>朱可夫NUK17双持冲锋枪<br> D+500<br> 从不复杂，但也从未让人失望。NUK系列下的双持微型冲锋枪向来有着不俗的销售业绩，但在懂行的人眼里，17型是系列最佳。<br> 这是两把体积2，武器伤害6L，弹夹容量30发，基础射程20M，具有【连射】的双持冲锋枪，双持冲锋枪无法拆开使用，单独使用时会失去所有效果。<br> 特殊的，双持冲锋枪在进行连射时只会消耗前30发子弹，它的弹夹只能被它自带的效果和特性增容，在进行一次连射时，若弹夹中的子弹多于30发，则可以再至少消耗10发子弹，每10发额外消耗的子弹会使本次攻击额外获得1点检定上的增强加值，并再可以额外选择攻击范围内的另一个目标同时对其攻击。双持冲锋枪不能获得无限子弹特性，换弹是一个迅捷动作。</p><p>每场影片结束时，都可以额外依次选择一项改装项目，同一行只能选择一种改装，选择后不能更换。</p><ol><li></li></ol><p>扩容弹袋（总弹药量）<br> 你不得不少带几个三明治，但你的总备弹量增加了！<br> 获得一个体积为3立方米的储物空间，当你需要换弹时，可以从这个储物空间中使用自由动作直接取出弹药，其中储存的弹药需要自行购买。</p><p>高速子弹（伤害）<br> 研发部加班造成的身体与精神上的伤害，换取了武器的整体伤害提升。<br> 在选择这项改造时，它会额外提升2L武器伤害。</p><ol start="2"><li></li></ol><p>大容量弹匣（弹匣容量）<br> 要说弹夹、弹匣、弹鼓、燃料箱的共同优点…你总能找到比它们大一点点的型号。<br> 在选择这项改造时，双持冲锋枪会扩大20发载弹量。</p><p>超载供弹结构（射速）<br> 我们超频了你的枪，现在它射的更快了。别多问，这种东西小范围享受就可以了。也别让管理层知道。<br> 在选择这项改造后，双持冲锋枪的连射会额外获得3点高速。</p><ol start="3"><li></li></ol><p>大口径弹药（伤害）<br> 研发部加班造成的身体与精神上的伤害，换取了武器的整体伤害提升。<br> 双持冲锋枪的武器伤害提升3L。</p><p>改良配重（精准度）<br> 提升基础精准度。<br> 在使用朱可夫NUK17双持冲锋枪时，你额外获得1点瞄准上限，并视为已经瞄准了1轮。</p><ol start="4"><li></li></ol><p>贯通弹（穿透）<br> 异形弹头被设计成能以最小的动能损失穿透目标的造型，换句话说：一发直接射穿一个敌人！<br> 在选择这项改造时，它会额外获得【贯穿】效果。</p><p>空尖弹（弱点伤害加成）<br> 哪里发光点哪里！我们加强了武器对生物肉质部位的伤害。不用客气。<br> 现在，使用重型左轮攻击特殊部位时，将忽略至多3点特殊部位减值。</p><ol start="5"><li></li></ol><p>导电子弹（电击）<br> 对触电状态下的敌人造成更多伤害。<br> 对具有麻痹点数的敌人进行射击会额外获得1点攻击上的附加成功。</p><p>来去自如（移动速度）<br> 射空弹夹后获得短暂移速加成。<br> 在一次射空所有弹夹的射击后，立刻获得15点额外的移动速度直到回合结束。</p><p>在双持冲锋枪至少具有2种改装后，便可以解锁模组栏位，并解锁模组的购买权，这把枪只能同时享受一种模组带来的效果。在具有模组后，双持冲锋枪的武器伤害将再提升6点。</p><p>精简弹匣<br> C+1000<br> 无瑕超频模组<br> 移除弹匣上的非必要结构材料，更轻的匣体让换弹时弹匣更快弹出，同时更加顺畅的供弹变相地略微提升了射速。<br> +更快的换弹速度<br> +提高射速<br> 现在，在一次使用双持冲锋枪射击的过程中，你可以通过使用数个迅捷动作连续在射击进行的过程中换弹，每更换一个弹夹需要1个迅捷动作，这意味着你可以一边射击一边换弹，从而获得更多的连射子弹数，最多能在一次射击中更换两个弹夹，在那之后便必须停止射击。</p><p>定制弹壳<br> C+1000<br> 均衡超频模组<br> 在每个弹匣里塞进更多的定制弹药，但射速会略微降低。<br> +显著提升弹匣容量<br> -降低射速<br> 弹夹容量额外提升75，但是每连射20发就需要额外消耗5发子弹，初始连射获得的加值-3，不进行连射时不触发效果。</p><p>内置起爆<br> C+1000<br> 不稳定超频模组<br> 内置微型炸药的特殊子弹，会在你换弹时引爆。代价是降低弹匣容量和直接伤害。<br> +换弹时引爆射入目标体内的微型炸药，造成大量伤害。<br> -显著减少直接伤害<br> -显著增加换弹速度<br> -降低弹匣容量<br> 对于你成功对其命中且造成伤害的目标而言，那个目标还需要进行一次强韧豁免检定以对抗伤害出目，对抗失败时，二者每有1点差值，就对其造成1点潜在的剧痛点数，本次攻击造成的伤害只会造成原伤害出目一半的伤害。<br> 弹匣容量降低为20发，换弹动作上升为移动动作，且无法被任何能力降低动作。当你进行换弹时，立即生效所有潜在剧痛点数。</p><p>热气回收<br> C+1000<br> 不稳定超频模组<br> 特殊的硬质子弹加上将开火时的逃逸气流重引回膛极大地提升了武器的基础伤害，但也让武器更难以控制，此外，这种子弹也无法对弱点造成任何伤害。<br> +显著提升伤害和护甲破坏效果<br> -扩大基础散布<br> -无弱点伤害加成<br> -更慢的射击后移动速度<br> 使用双持冲锋枪进行连射攻击时，连射消耗的基础子弹数会下降到10发，因双持冲锋枪的能力额外消耗的子弹提供的加值将变为*3的武器伤害，失去额外攻击目标能力，并再提供每10发2点破甲。<br> 双持冲锋枪将无法再攻击目标特殊部位，也无法在进行过瞄准攻击的下一回合进行瞄准，在射击结束后的这一轮内移动时，额外失去15点基础移速（最多下降至1）。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',25)])])}const f=b(o,[["render",n]]);export{N as __pageData,f as default};
